module johnson_counter(
	input clk,
	input reset,
	output reg [4:0] q);
always @(posedge clk) begin
	if (reset)
		q <= 0;
	else
		q <= {~q[0], q[4:1]};
end

  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        q <= 32'hFFFFFFFF;
      end else begin
        q <= 32'h00000000;
      end;
    end
  end

endmodule

